sql.where:
p.USE_YN = 'Y'
AND p.CREATE_USER_ID = #{userId}

AND p.PAGE_TYPE = 'PAGE'

    AND p.APPROVE_STATE = #{req.approveState}


    AND p.VIEW_MODE = #{req.viewMode}


    AND p.PAGE_NAME LIKE '%' || #{req.search} || '%'

mapper.select:
SELECT * FROM (
    SELECT INNER_QRY.*, ROWNUM AS RNUM FROM (
        SELECT

        FROM SPW_CMS_PAGE p


    ) INNER_QRY
    WHERE ROWNUM <= #{endRow}
) WHERE RNUM > #{offset}

SELECT COUNT(*)
FROM SPW_CMS_PAGE
WHERE PAGE_ID        = #{pageId}
  AND CREATE_USER_ID = #{userId}
  AND USE_YN         = 'Y'

SELECT COUNT(*)
FROM SPW_CMS_PAGE_HISTORY
WHERE PAGE_ID = #{pageId}

mapper.update:
UPDATE SPW_CMS_PAGE
SET USE_YN              = 'N',
    LAST_MODIFIER_ID    = #{userId},
    LAST_MODIFIED_DTIME = SYSTIMESTAMP
WHERE PAGE_ID        = #{pageId}
  AND CREATE_USER_ID = #{userId}

mapper.delete:
DELETE FROM SPW_CMS_PAGE
WHERE PAGE_ID        = #{pageId}
  AND CREATE_USER_ID = #{userId}
  AND USE_YN         = 'Y'
